  }, "{due:2024-01-20}"), " ", mdx("inlineCode", {
    parentName: "p"
  }, "@2h30m"), "\n\uACB0\uAD6D \uBCF5\uC2B5 \uC2DC\uAC04\uC774\uB77C\uB294 \uC2DC\uAC04\uC774 \uAF2D \uD544\uC694\uD574. \uC790\uAE30\uC804 \uB9C8\uC9C0\uB9C9 1\uC2DC\uAC04\uC740 \uADF8\uAC78\uB85C \uC4F8\uC218\uBC16\uC5D4 \uC5C6\uB124. \uC54C\uCC2C \uC2DC\uAC04\uC744 \uC4F0\uB824\uBA74. \uADF8\uB7FC \uB0B4 \uD504\uB85C\uC81D\uD2B8 \uD560\uC2DC\uAC04\uC774 \uC880 \uC5C6\uB294\uB370.. \uADF8\uB7EC\uBA74 \uD3C9\uC18C \uC5EC\uC720 1\uC2DC\uAC04\uC744 \uC774\uB3D9\uC774\uB098 \uCC45\uBCF4\uB294\uB370 \uC4F4\uB2E4\uACE0 \uCE58\uBA74, \uC544\uCE68\uC5D0 \uC77C\uC5B4\uB098\uB294 \uC2DC\uAC04\uBC16\uC5D0\uB294 \uC5C6\uC5B4. \uADF8\uB798\uC11C 7\uC2DC\uCBE4 \uC77C\uC5B4\uB098\uBA74 \uC88B\uB2E4\uB294\uAC70\uC9C0. \uC2DC\uAC04 \uBC84\uB2C8\uAE4C, \uC0DD\uAE30\uB2C8\uAE4C.\n11\uC2DC\uC5D0\uB294 \uC790\uC57C\uD558\uACE0, \uADF8 \uC804\uC5D0 \uB9C8\uBBF8\uB791\uB3C4 \uC2DC\uAC04\uC744 \uBCF4\uB0B4\uC57C\uD558\uB2C8\uAE4C.\n\uBB34\uC870\uAC74 \uC544\uCE68\uC740 \uD544\uC218\uB77C\uACE0 \uBD10\uC57C\uACA0\uB124. \uC2DC\uAC04\uC774\uB77C\uB294 \uB3C8\uC744 \uBC8C\uB824\uBA74. \uC774\uAC83\uB3C4 \uC77C\uC778\uAC70\uC57C. \uC544\uCE68\uC5D0 \uC77C\uC5B4\uB098\uB294 \uC790\uCCB4\uAC00 \uD558\uB098\uC758 \uC77C\uC774\uC57C. \uC2DC\uAC04 \uBC84\uB294 \uC77C\uC774\uC9C0.\n\uADF8\uB9AC\uACE0\uB098\uC11C \uC8FC\uB9D0\uC5D0 \uC774\uC81C \uD558\uB8E8\uC815\uB3C4, \uC544\uB2C8\uBA74 \uC2DC\uAC04\uC744 \uCABC\uAC1C\uB358\uC9C0 \uD574\uC11C 10\uC2DC\uAC04 \uC815\uB3C4 \uB9CC\uB4E4\uBA74, \uC774\uAC74 \uB098\uB9CC\uC758 \uC628\uC804\uD55C \uC2DC\uAC04\uB3C8\uC774 \uB418\uC9C0.\n\uB2A6\uC7A0\uC880 \uC790\uACE0 \uC5EC\uD589\uAC04\uB2E4\uACE0 \uD574\uB3C4 \uC544\uCE68\uC5D0 \uD55C 2\uC2DC\uAC04 \uCE74\uD398, \uC800\uB141\uC5D0 \uD55C 2\uC2DC\uAC04\uD558\uBA74 8\uC2DC\uAC04\uC740 \uB098\uC624\uB2C8\uAE4C \uC9EC\uC9EC\uC774 \uBC25\uBA39\uACE0 15\uBD84\uC529 4\uBC88\uD574\uC11C 1\uC2DC\uAC04 \uBC8C\uBA74 \uBD88\uAC00\uB2A5\uD55C\uAC74 \uC544\uB2D8."), mdx("p", null, "\uBBF8\uB798\uB97C \uC704\uD55C \uC0DD\uC0B0\uC131 \uC124\uACC4\uB3C4\uAC00 \uAF3C\uAF3C\uD558\uACE0 \uD2BC\uD2BC\uD560\uC218\uB85D \uC88B\uAE34\uD558\uB2C8\uAE4C \uB098\uB984\uB300\uB85C \uD53C\uB77C\uBBF8\uB4DC\uB97C \uC138\uC6B8 \uC900\uBE44\uB77C\uACE0 \uCE58\uC790. \uADF8\uB0E5 \uB0AD\uBE44\uD55C \uC2DC\uAC04\uB3C4 \uB9CE\uAE34\uD558\uC9C0\uB9CC...\n\uC65C\uB0D0\uBA74 \uD68C\uC0AC\uC5D0\uC11C\uB294 \uD3C9\uC77C 40\uC2DC\uAC04\uC774\uB098 \uB418\uB294 \uC2DC\uAC04\uC744 \uC4F0\uC9C0\uB9CC \uB0B4 \uC77C\uC5D0\uB294 10\uC2DC\uAC04\uB3C4 \uBABB\uC4F0\uACE0 \uAC00\uC871\uC5D0\uAC8C\uB3C4 12\uC2DC\uAC04 \uC815\uB3C4\uBC16\uC5D4 \uBABB\uC4F0\uB2C8 \uD68C\uC0AC\uC5D0\uC11C \uC77C\uC8FC\uC77C \uAC78\uB9B4\uAC70 \uD63C\uC790\uD558\uBA74 \uD55C\uB2EC\uC740 \uAC78\uB9AC\uB294 \uC148\uC774\uC9C0. \uC0DD\uC0B0\uC131\uC5D0 \uBAA9\uB9EC\uC218\uBC16\uC5D0\uB294 \uC5C6\uB294\uAC70\uC57C. \uD68C\uC0AC\uC5D0\uC11C \uD30C\uC774\uC36C\uC744 \uC4F0\uB4E0 \uC790\uBC14\uB97C \uC4F0\uB4E0 dont care. \uB098\uB294 elm \uC4F0\uACE0 haskell \uC368\uC57C\uD558\uB294 \uC774\uC720\uC774\uAE30\uB3C4 \uD55C\uAC70\uC9C0. \uCC98\uC74C\uC5D0\uB294 \uB290\uB9AC\uACE0 \uC5B4\uB824\uC6CC\uB3C4 \uB098\uC911\uC5D0 \uAC00\uC18D\uB3C4\uAC00 \uBD99\uC744\uD14C\uB2C8\uAE4C. "), mdx("p", null, "\uB9C8\uC9C0\uB9C9\uC73C\uB85C, \uD1A0\uB9C8\uD1A0 \uD3EC\uBAA8\uB3C4\uB85C \uB3CC\uB9B4\uB54C\uB294 \uBC18\uB4DC\uC2DC \uC544\uD1A0\uBBF9\uD558\uAC8C \uD558\uB098\uC758 \uC77C\uC5D0\uB9CC \uC9D1\uC911\uD560\uAC83. \uADF8\uB9AC\uACE0 \uC608\uC804\uCC98\uB7FC \uD1A0\uB9C8\uD1A0 \uAC1C\uC218 \uB123\uC5B4\uB3C4 \uC88B\uC744\uAC83 \uAC19\uACE0.\uD83C\uDF31 \uD83C\uDF33 \uC774\uAC70 \uB9D0\uC57C.\n\uADFC\uB370 \uC774\uAC70\uB294 \uC880 \uC774\uC0C1\uD558\uAE34\uD574 \uD83C\uDF3110\uAC1C\uB97C \uD83C\uDF331\uAC1C\uB85C \uCE58\uB294\uAC8C \uB0AB\uC9C0\uC54A\uC744\uAE4C? \uADFC\uB370 \uC544\uBB34\uB9AC \uB9CE\uC544\uB3C4 10\uAC1C\uB294 \uC548\uB098\uC624\uC9C0 \uC54A\uB098? \uD558\uB8E8 \uC885\uC77C 8\uC2DC\uAC04 \uBD99\uC5B4\uC788\uC5B4\uB3C4 2h30m\uC774 \uD55C \uC0AC\uC774\uD074\uC778\uB370 3\uC0AC\uC774\uD074 \uB3CC\uBA74 \uB05D\uC784. \uB0A8\uB294 \uC790\uD22C\uB9AC 30\uBD84 \uC815\uB3C4\uB294 \uD68C\uC0AC\uC0AC\uB78C\uB4E4\uC774\uB098 \uC8FC\uBCC0 \uCEE4\uBBA4\uB2C8\uD2F0, \uCE5C\uAD6C\uB4E4 \uCC59\uAE30\uB4E0\uAC00 \uD558\uACE0 \uAC00\uB054\uB0B4\uB294 \uD734\uAC00\uB098 \uD30C\uD2F0\uB098 \uAC00\uC871\uB4E4 \uBAA8\uC784 \uC774\uB7F0\uAC70 \uD558\uBA74 \uB418\uACE0, \uADF8 \uBE44\uC728\uB3C4 \uC880 \uC815\uD574\uC57C\uD558\uB294\uB370 \uC720\uB3D9\uC801\uC73C\uB85C \uCC9C\uCC9C\uD788 \uC138\uC6B0\uC790. \uC77C\uB2E8 \uAE09\uD55C\uAC74 \uB8E8\uD2F4\uC774\uB2C8\uAE4C.\n\uB300\uCDA9 \uC0DD\uAC01\uD574\uBCF4\uBA74 \uC77C\uB2E8 \uACF5\uC2DD\uC801\uC73C\uB85C \uD68C\uC0AC\uC5D0\uC11C\uC8FC\uB294 \uC5F0\uCC28, \uD734\uAC00 \uC774\uB7F0\uAC74 \uC804\uBD80 \uAC00\uC871, \uCE5C\uAD6C\uC5D0 \uC4F0\uB294\uAC78\uB85C \uD558\uC790. \uC8FC\uB9D0\uBE7C\uACE0. \uB300\uCDA9 15\uAC1C\uBA74 7\uC77C\uC815\uB3C4, 5h\uC529 \uC4F4\uB2E4\uACE0 \uD558\uBA74 35h /1Y...\n\uADF8\uB0E5 \uB531 \uC801\uB2F9\uD558\uAC8C \uAC00\uC871\uC774\uB098 \uAC00\uAE4C\uC6B4 \uCE5C\uAD6C\uC5D0\uAC8C 80~90h, \uCEE4\uBBA4\uB2C8\uD2F0 \uAD00\uB9AC\uC5D0 60~70\uC815\uB3C4 \uD558\uBA74 \uD569\uCCD0\uC11C 150h \uC815\uB3C4 \uB098\uC634."), mdx("p", null, "#\uB9E4\uBAB0\uBE44\uC6A9 #\uC2DC\uAC04\uAD00\uB9AC "));
