  }, "\uACB0\uACFC\uAC00 \uC544\uB2CC \uACFC\uC815\uC744 \uC774\uBBF8\uC9C0 \uD2B8\uB808\uC774\uB2DD\uD558\uACE0 \uBBF8\uB798\uC644\uB8CC \uC2DC\uC810\uC744 \uC0AC\uC6A9\uD558\uC5EC \uACC4\uD68D\uD55C\uB2E4. \uC989, \uC9C0\uAE08\uBD80\uD130 \uD574\uC11C \uCC28\uACE1\uCC28\uACE1 \uB05D\uB0C8\uB2E4 \uB77C\uB294 \uC131\uCDE8\uB97C \uAC15\uC870\uD558\uB294\uAC83. \uBBF8\uB798\uC5D0 \uD55C\uB2E4, \uD560\uAC83\uC774\uB2E4 \uB77C\uB294 \uC5B4\uC815\uCA61\uD55C \uD76C\uB9DD\uC774 \uC544\uB2CC \uAC01\uC624\uAC00 \uD544\uC694\uD558\uB2E4\uB294 \uB9D0. \uC2DC\uAC04\uBCF4\uB2E4 \uD560\uC77C\uC774 \uC6B0\uC120\uC774\uB2E4. \uD560\uC77C\uC744 2\uBC88\uC5D0\uC11C \uC798 \uCE21\uC815\uD574\uC11C \uC2DC\uAC04\uC744 \uBD80\uC218\uC801\uC73C\uB85C \uC0AC\uC6A9\uD574\uC57C \uC2DC\uAC04\uC5D0 \uB04C\uB824\uB2E4\uB2C8\uC9C0\uC54A\uACE0 \uC2DC\uAC04\uC744 \uC774\uB04C\uC218\uC788\uB2E4. \uBE44\uAD50\uD558\uC9C0\uB9D0\uACE0 \uB0B4\uBA74\uC758 \uB098 \uC790\uC2E0\uC758 \uC2E4\uC81C \uB2A5\uB825\uCE58\uB97C \uAE30\uC900\uC73C\uB85C \uC0BC\uC544\uB77C. \uAC70\uAE30\uC11C \uBD80\uC871\uD568\uC744 \uB290\uB07C\uAC70\uB098 \uBD84\uD558\uBA74 \uC5F0\uC2B5\uC744 \uD1B5\uD574 \uD6A8\uC728\uC744 \uB354 \uB04C\uC5B4\uC62C\uB824\uB77C.")), mdx("li", {
